function formatDate(dateStr){if(!dateStr)return"";const[year,month,day]=dateStr.split("-").map(Number);const date=new Date(year,month-1,day);return date.toLocaleDateString("en-US",{year:"numeric",month:"short",day:"numeric"})}function createCard(item,index=0,eagerThreshold=8){const card=document.createElement("article");card.className="card";const watchedHTML=item.watched?`<p class="card-date">Finished Watching:<br>${formatDate(item.watched)}</p>`:"";const loadingAttr=index<eagerThreshold?"eager":"lazy";card.innerHTML=`
        <div class="poster-container">
            <img src="${item.poster}" 
                 loading="${loadingAttr}" 
                 width="200" 
                 height="300"
                 alt="${item.title} Poster">
        </div>
        <div class="card-content">
            <h3 class="card-title">${item.title}</h3>
            <p class="card-rating">${item.rating}</p>
            ${watchedHTML}
        </div>
    `;card.onclick=()=>openModal(item.title,item.review);return card}function extractRatingScore(ratingStr){const match=ratingStr.match(/\((\d+(\.\d+)?)\/10\)/);return match?parseFloat(match[1]):0}function sortCategoryData(data){return[...data].sort((a,b)=>{const scoreA=extractRatingScore(a.rating);const scoreB=extractRatingScore(b.rating);if(scoreA!==scoreB)return scoreB-scoreA;const weightA=a.weight??9999;const weightB=b.weight??9999;if(weightA!==weightB)return weightA-weightB;const dateA=a.watched?new Date(a.watched):new Date(0);const dateB=b.watched?new Date(b.watched):new Date(0);return dateB-dateA})}function setupCollapsibleTiers(){const tierHeaders=document.querySelectorAll(".tier-header");tierHeaders.forEach(header=>{header.addEventListener("click",function(e){if(e.target.closest("a, button"))return;const gridId=this.id.replace("-header","");const grid=document.getElementById(gridId);if(!grid)return;const isCollapsed=grid.classList.contains("collapsed");if(isCollapsed){grid.classList.remove("collapsed");this.classList.remove("collapsed");setTimeout(()=>{grid.style.display="grid"},10)}else{grid.classList.add("collapsed");this.classList.add("collapsed");setTimeout(()=>{if(grid.classList.contains("collapsed")){grid.style.display="none"}},300)}})})}function setupSearch(){const searchInput=document.getElementById("searchInput");if(!searchInput)return;const unrankedHeader=document.getElementById("unranked-header");const unrankedGrid=document.getElementById("unranked-tier");let wasCollapsed=false;let userManuallyOpened=false;searchInput.addEventListener("input",e=>{const searchTerm=e.target.value.toLowerCase().trim();let totalVisible=0;let unrankedHasMatches=false;document.querySelectorAll(".card").forEach(card=>{const title=card.querySelector(".card-title").textContent.toLowerCase();const matches=searchTerm===""||title.includes(searchTerm);card.style.display=matches?"":"none";if(matches)totalVisible++});if(unrankedGrid&&unrankedHeader){const unrankedCards=unrankedGrid.querySelectorAll(".card");const visibleUnranked=Array.from(unrankedCards).filter(card=>card.style.display!=="none").length;unrankedHasMatches=visibleUnranked>0;const isCollapsed=unrankedGrid.classList.contains("collapsed");if(searchTerm!==""&&unrankedHasMatches&&isCollapsed&&!userManuallyOpened){wasCollapsed=true;unrankedGrid.style.display="grid";unrankedGrid.classList.remove("collapsed");unrankedHeader.textContent=unrankedHeader.textContent.replace("▶","▼")}else if(searchTerm===""&&wasCollapsed&&!userManuallyOpened){unrankedGrid.classList.add("collapsed");unrankedHeader.textContent=unrankedHeader.textContent.replace("▼","▶");setTimeout(()=>{if(unrankedGrid.classList.contains("collapsed")){unrankedGrid.style.display="none"}},400)}}const totalCount=document.getElementById("total-count");if(totalCount){if(searchTerm===""){totalCount.textContent=window.categoryData.length}else{totalCount.textContent=totalVisible}}});if(unrankedHeader&&unrankedGrid){unrankedHeader.addEventListener("click",()=>{const isCollapsed=unrankedGrid.classList.contains("collapsed");if(isCollapsed){userManuallyOpened=true;wasCollapsed=false}else{userManuallyOpened=false}})}}function getVisibleCardCount(){const grid=document.querySelector(".grid");if(!grid)return 8;const gridStyle=getComputedStyle(grid);const columns=gridStyle.gridTemplateColumns.split(" ").length;const viewportHeight=window.innerHeight;const gridTop=grid.getBoundingClientRect().top;const availableHeight=viewportHeight-gridTop;const cardHeight=300;const visibleRows=Math.ceil(availableHeight/cardHeight);return columns*visibleRows}function populateCards(){if(!window.categoryData){console.error("Failed to load category data. Check that data.yml exists and is valid.");return}const totalCount=document.getElementById("total-count");const libraryCount=document.getElementById("library-count");if(totalCount){totalCount.textContent=window.categoryData.length}if(libraryCount){const countableItems=window.categoryData.filter(item=>item.count!==false);libraryCount.textContent=countableItems.length}const sortedData=sortCategoryData(window.categoryData);const eagerLoadCount=getVisibleCardCount();let globalIndex=0;sortedData.forEach(item=>{const tierGrid=document.getElementById(`${item.tier}-tier`);if(tierGrid){tierGrid.appendChild(createCard(item,globalIndex,eagerLoadCount));globalIndex++}});setupCollapsibleTiers();setupSearch()}const modal=document.getElementById("reviewModal");const modalTitle=document.getElementById("modalTitle");const modalReview=document.getElementById("modalReview");const closeBtn=document.querySelector(".close");function openModal(title,review){modalTitle.textContent=title+" Review";modalReview.innerHTML=review.replace(/\n/g,"<br>");modal.style.display="block";document.body.style.overflow="hidden";setTimeout(()=>{modal.classList.add("show")},10)}function closeModal(){modal.classList.remove("show");setTimeout(()=>{modal.style.display="none";document.body.style.overflow=""},300)}closeBtn.onclick=closeModal;window.onclick=event=>{if(event.target===modal)closeModal()};document.addEventListener("keydown",event=>{if(event.key==="Escape"&&modal.classList.contains("show")){closeModal()}});const backToTopBtn=document.getElementById("backToTop");if(backToTopBtn){window.addEventListener("scroll",()=>{if(window.scrollY>300){backToTopBtn.classList.add("visible")}else{backToTopBtn.classList.remove("visible")}});backToTopBtn.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"})})}